public class Main {
    public static void main(String[] args) {
        Editor ed = new Editor();
        ed.insert(0, "Hello");
        ed.undo();
        System.out.println(ed.getText().isEmpty() ? "UNDO_OK" : "UNDO_FAIL:" + ed.getText());
    }
}

/* Test driver */
public class Main {
    public static void main(String[] args) {
        Editor ed = new Editor("abc");
        ed.delete(0, 1);
        ed.undo();
        ed.redo();
        System.out.println(ed.getText().equals("bc") ? "REDO_OK" : "REDO_FAIL:" + ed.getText());
    }
}

/* Test driver */
public class Main {
    public static void main(String[] args) {
        Document doc = new Document("snapshot-me");
        DocumentMemento m = doc.save();
        doc.insert(0, "GARBAGE-");
        doc.restore(m);
        System.out.println(doc.getText().equals("snapshot-me") ? "MEMENTO_OK" : "MEMENTO_FAIL:" + doc.getText());
    }
}
